import{_ as e,o as r,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F04: 業外收支純度與收益質量 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260512/F04_業外收支純度與收益質量.md","filePath":"審計報告庫/財務審計/6261_久元/20260512/F04_業外收支純度與收益質量.md"}'),i={name:"審計報告庫/財務審計/6261_久元/20260512/F04_業外收支純度與收益質量.md"};function t(n,a,h,s,d,c){return r(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="f04-業外收支純度與收益質量-財務審計專家報告" tabindex="-1">F04: 業外收支純度與收益質量 - 財務審計專家報告 <a class="header-anchor" href="#f04-業外收支純度與收益質量-財務審計專家報告" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>業外收支的佔比及本質為何？收益質量是否純淨？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：OP/稅前比120%→45.6%業外佔逾半。2024處分7,512萬+2025補助5,194萬匯兌3,998萬。Core EPS 1.05 vs帳面1.53</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：截至2025年合併財報及附註</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：OP 2.81→0.56→1.09億。業外佔稅前比-20%→62%→54%。補助0.52+匯兌0.40+租金0.33億。帳面EPS 1.53元但Core EPS約1.05元差距31%。2024 OP暴跌80%靠處分7,512萬撐獲利。業外連兩年佔稅前逾50%收益品質低。</li><li><strong>診斷見解</strong>：營業利益從2.81億降至1.09億(-61%)，業外補貼佔比過半含大量一次性與波動項目，扣除後核心獲利僅帳面七成，真實每股盈餘被業外顯著美化。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="業外佔比與結構" tabindex="-1">業外佔比與結構 <a class="header-anchor" href="#業外佔比與結構" aria-label="Permalink to &quot;業外佔比與結構&quot;">​</a></h3><p>業外/稅前比：2023年-20.2%(業外損失)→2024年62.2%→2025年54.4%。2024年0.93億中含7,512萬處分子公司一次性利益。2025年1.30億中補助5,194萬(專案非經常)+匯兌3,998萬(波動)+租金3,334萬(穩定)。若補助到期，業外短少5,194萬(EPS0.40元)。</p><h3 id="營業利益真實能力" tabindex="-1">營業利益真實能力 <a class="header-anchor" href="#營業利益真實能力" aria-label="Permalink to &quot;營業利益真實能力&quot;">​</a></h3><p>OP 2.81→0.56→1.09億。2024崩跌主因自有產品獲利從2.29降至1.53億(-33%)，代工維持4.3億。2025自有回升至1.69億但代工微降至4.0億。OP仍遠低於2023水準，反映本業結構性弱化。</p><h3 id="收益品質綜合評價" tabindex="-1">收益品質綜合評價 <a class="header-anchor" href="#收益品質綜合評價" aria-label="Permalink to &quot;收益品質綜合評價&quot;">​</a></h3><p>Core Earnings=OP+租金+利息=1.71億，帳面稅前2.39億差額0.68億(28%)來自一次性/波動項。Core EPS約1.05元。2024更極端：帳面EPS 1.00元但Core EPS約0.32元。PER 29倍以Core EPS計實為42倍。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點" tabindex="-1">🔴 空方觀點 <a class="header-anchor" href="#🔴-空方觀點" aria-label="Permalink to &quot;🔴 空方觀點&quot;">​</a></h3><ol><li>OP從2.81→1.09億(-61%)，業外佔稅前連兩年逾50%，收益品質極不純淨，本業獲利下滑趨勢令人憂慮</li><li>補助5,194萬(專案)+匯兌3,998萬(波動)+處分7,512萬(一次性)合計佔2025稅前55%，全剔除Core EPS僅1.05元，業外依賴度過高實為獲利品質惡化警訊</li><li>補助到期+台幣升值+無處分利益=2026年業外恐縮至0.5-0.7億，EPS壓力降至1.0-1.2元下行空間顯著</li></ol><h3 id="🟢-多方觀點" tabindex="-1">🟢 多方觀點 <a class="header-anchor" href="#🟢-多方觀點" aria-label="Permalink to &quot;🟢 多方觀點&quot;">​</a></h3><ol><li>2025 OP從0.56翻倍至1.09億，自有產品獲利回升改善方向明確</li><li>利息0.29+租金0.33=0.62億為穩定經常性業外，每年貢獻EPS約0.48元</li><li>補助具政策延續性，若2026年續期補助收入可能延續</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>收益品質偏低—業外佔比過高含大量一次性/波動項。核心EPS約1.0-1.1元vs帳面1.53元差距30-35%。若以本業獲利評估，當前PER過高。改善關鍵在營收恢復增長帶動OP回升。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>原始數據：FinMind TaiwanStockFinancialStatements(OperatingIncome,TotalNonoperatingIncomeAndExpense,PreTaxIncome)</li><li>年報附註：2025 Q4合併財報第57頁</li><li>數據查詢日期：2026-05-12</li></ul>',23)])])}const _=e(i,[["render",t]]);export{u as __pageData,_ as default};
